namespace optiling {

// UB model:
//   inQueueA: 1 * tileLen (dim floats)
//   inQueueP: 1 * tileLen
//   inQueueN: 1 * tileLen
//   tmp: diffPos, diffNeg, workspace: 3 * tileLen
//   total floats = 6 * tileLen => bytes = 24 * tileLen
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 64;  // small-aligned since dim may be variable

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    TripletMarginLossCustomTilingData tiling;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *margin = attrs->GetAttrPointer<float>(0);

    // Correct way to get origin shape dimensions (fix compilation error)
    const gert::StorageShape *storageShape = context->GetInputShape(0);
    const gert::Shape &originShape = storageShape->GetOriginShape();
    uint32_t ndim = originShape.GetDimNum();
    if (ndim != 2) {
        return ge::GRAPH_FAILED;
    }
    int64_t dim0 = originShape.GetDim(0);
    int64_t dim1 = originShape.GetDim(1);
    uint32_t batchSize = static_cast<uint32_t>(dim0);
    uint32_t dim = static_cast<uint32_t>(dim1);
    uint32_t totalLength = batchSize * dim;

    // tileLength = dim (we process one sample at a time)
    uint32_t tileLen = dim;
    // Align to 64 for DataCopy performance
    uint32_t alignedTile = AlignDown(tileLen, ALIGN_ELEMS);
    if (alignedTile > 0) tileLen = alignedTile;
    // Ensure tileLen ≥ 1
    if (tileLen == 0) tileLen = dim;

    // Only one block processes all samples
    context->SetBlockDim(1);

    tiling.set_batchSize(batchSize);
    tiling.set_dim(dim);
    tiling.set_margin(*margin);
    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(1);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

